import{c as e,Q as a,j as o,m as r}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Claude Code的32个使用技巧 - 入门，进阶，高阶 — @elliotchen100","description":"","frontmatter":{"title":"Claude Code的32个使用技巧 - 入门，进阶，高阶 — @elliotchen100","author":"艾略特（@elliotchen100）","date":"2026-04-29T00:00:00.000Z","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-29-@elliotchen100-2393.md","filePath":"research/tweets/2026-04-29-@elliotchen100-2393.md","lastUpdated":1779796674000}'),n={name:"research/tweets/2026-04-29-@elliotchen100-2393.md"};function l(i,t,p,d,s,c){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="claude-code的32个使用技巧-入门-进阶-高阶-—-elliotchen100" tabindex="-1">Claude Code的32个使用技巧 - 入门，进阶，高阶 — @elliotchen100 <a class="header-anchor" href="#claude-code的32个使用技巧-入门-进阶-高阶-—-elliotchen100" aria-label="Permalink to &quot;Claude Code的32个使用技巧 - 入门，进阶，高阶 — @elliotchen100&quot;">​</a></h1><p><strong>来源</strong>：<a href="https://x.com/elliotchen100/status/2049299210668032393" target="_blank" rel="noreferrer">https://x.com/elliotchen100/status/2049299210668032393</a><strong>作者</strong>：艾略特（@elliotchen100） <strong>发布日期</strong>：2026-04-29 <strong>收录日期</strong>：2026-04-29 <strong>类型</strong>：Twitter Article <strong>统计</strong>：101 likes · 19 retweets · 268 bookmarks · 25090 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>昨天看到 @nateherk 的这个 YouTube 视频，觉得很不错，推荐一下。</p><p><a href="https://www.youtube.com/watch?v=jqoFP9QapXI" target="_blank" rel="noreferrer">https://www.youtube.com/watch?v=jqoFP9QapXI</a></p><p>他的视频风格我一直挺喜欢，简简单单清清楚楚，没有废话，开头不卖关子，结尾不拖泥带水。这条尤其密集，32 个技巧塞进 16 分钟，按入门，进阶，高阶分了三档，从 /init 一路讲到 agent team。</p><p>我先把内容快速过一遍，再挑 6 个我觉得视频里讲到了但没展开，其实最关键的点，把背后的原理拆开讲。</p><h3 id="_32-个技巧速览" tabindex="-1">32 个技巧速览 <a class="header-anchor" href="#_32-个技巧速览" aria-label="Permalink to &quot;32 个技巧速览&quot;">​</a></h3><p><strong>入门</strong> /init 一键生成项目说明书 cloud.md plan mode 开局先规划再动手 /context 看 token 占用，超 60% 用 /compact 压缩 把 Claude 当 junior 同事，提问题不要下命令 self check 加进 todo，让它自己验自己</p><p><strong>进阶</strong> sub agents 并行任务，独立 context 不打架 custom skills 复用 prompt 文件 简单活儿扔给 Haiku 省 token 跑偏了直接 exit 重prompt 截图喂回去做视觉 debug</p><p><strong>高阶</strong> /loop 自动跑 recurring tasks，最长 3 天 Git worktrees 多 session 并行 VPS 托管不掉线，手机也能远程操控 ultrathink 模式给硬骨头分配最大 token agent team 多 agent 协作分工</p><p>先看这个清单，和其他 Claude Code 教程没差别，能搜到的太多了。Nate Herk 这条视频的真正价值，是他用老手的视角把这些点串起来了。下面挑 6 个我觉得别人聊得最少，但其实最关键的，把背后的原理拆开讲。</p><h3 id="一、把-claude-当-junior-同事-不是态度问题-是-prompt-工程" tabindex="-1">一、把 Claude 当 junior 同事，不是态度问题，是 prompt 工程 <a class="header-anchor" href="#一、把-claude-当-junior-同事-不是态度问题-是-prompt-工程" aria-label="Permalink to &quot;一、把 Claude 当 junior 同事，不是态度问题，是 prompt 工程&quot;">​</a></h3><p>很多人看到这条会以为是「对它说话礼貌一点」。其实跟礼貌没关系，这是计算路径的选择。</p><p>LLM 接收命令式 prompt 时，触发的是「按指令执行」的浅层模式，直接 pattern match，输出快但思考浅。接收描述式 prompt 时，触发的是「理解后再行动」的深层模式，会展开 chain of thought，输出慢但准确度高一截。</p><p>同一个 bug，「修一下这里」和「这里看起来怪怪的，你查查为啥」出来的代码质量能差一倍。前者它就直接改你指出的那行，后者它会先去理解上下文，可能发现真正的问题在另一个地方。</p><p>更深一层，描述要具体且不带预设答案。「这里有 race condition」会让它只查 race condition，「这里偶尔会出错你查查」会让它展开完整排查。你 prompt 里预设的答案越少，激发的推理就越多。</p><h3 id="二、60-用-compact-是对抗-lost-in-the-middle-不是省-token" tabindex="-1">二、60% 用 /compact，是对抗 lost in the middle，不是省 token <a class="header-anchor" href="#二、60-用-compact-是对抗-lost-in-the-middle-不是省-token" aria-label="Permalink to &quot;二、60% 用 /compact，是对抗 lost in the middle，不是省 token&quot;">​</a></h3><p>这个 60% 经常被解读成「省 token 的阈值」。其实不是。</p><p>Stanford 2023 年有篇论文揭示了 lost in the middle 现象，LLM 在长 context 里的注意力是 U 型曲线，开头记得最牢，结尾记得最牢，中间最容易被忽略。</p><p>60% 这条线不是省钱的红线，是注意力开始衰减的经验线。超过这个点之后，你前面提过的关键需求会开始被「视而不见」，模型会犯一些「明明你说过了」的错。</p><p>/compact 真正的价值是它会保留关键决策和未完成事项，把中间的散乱讨论压掉。这不是粗暴截断，是在做注意力的重新聚焦。</p><p>判断什么时候该 compact，不要先看 token 数，要看模型是不是开始忘事。一旦它问出「你想做什么」之类的问题，立刻 compact，迟一步它就会带着错误前提继续往下做。</p><h3 id="三、跑偏了-exit-重开-是-token-经济学-不是耐心问题" tabindex="-1">三、跑偏了 exit 重开，是 token 经济学，不是耐心问题 <a class="header-anchor" href="#三、跑偏了-exit-重开-是-token-经济学-不是耐心问题" aria-label="Permalink to &quot;三、跑偏了 exit 重开，是 token 经济学，不是耐心问题&quot;">​</a></h3><p>很多人遇到 Claude 走偏，第一反应是「我再 prompt 它一下让它修正」。这个反应是错的。</p><p>被污染的 context 里，你写的修正 prompt 自己占 context，它的道歉占 context，它修正后的输出还会被错误推理影响。人类有 confirmation bias，LLM 也有，被前面的错误锚定之后很难真正跳出来。</p><p>总成本比重开高 2 到 3 倍，最终输出还可能更差。</p><p>应该建立的反射是 fail fast，看到走偏立刻 ESC，重新组织思路再 prompt，比让它自己踏回来快得多。重开不是失败，是更聪明的资源分配。</p><p>这个反射很多人建立不起来，因为觉得「重开是浪费」。其实越往后修，浪费越大。</p><h3 id="四、sub-agents-真正的价值是上下文隔离-不是并行" tabindex="-1">四、sub agents 真正的价值是上下文隔离，不是并行 <a class="header-anchor" href="#四、sub-agents-真正的价值是上下文隔离-不是并行" aria-label="Permalink to &quot;四、sub agents 真正的价值是上下文隔离，不是并行&quot;">​</a></h3><p>并行只是表象，隔离才是核心。</p><p>sub agents 把 context 从一维资源变成了树形资源。父 agent 是指挥者，看大局，不需要知道每个细节怎么实现。sub agent 是执行者，可以激进探索，包括各种失败和绕路。父 agent 只看 sub agent 的最终结论，那些失败的探索不会污染主线。</p><p>什么任务最适合开 sub agent，是「需要大量探索但只需要少量结论」的任务。比如「在 codebase 里找所有用了某个 deprecated API 的地方」，让 sub agent 把代码翻完，回来交一份清单就行。父 agent 不需要知道它翻过哪些文件，更不需要被它翻过的代码污染主上下文。</p><p>理解了这一点，你会发现很多任务都可以这样拆。「调研一下 X 库怎么用」「查一下这个 bug 在哪几个文件出现过」「列出所有需要改的测试」，全都是典型的 sub agent 任务。</p><h3 id="五、简单活儿扔给-haiku-不只是省钱-是避免「过度设计」" tabindex="-1">五、简单活儿扔给 Haiku 不只是省钱，是避免「过度设计」 <a class="header-anchor" href="#五、简单活儿扔给-haiku-不只是省钱-是避免「过度设计」" aria-label="Permalink to &quot;五、简单活儿扔给 Haiku 不只是省钱，是避免「过度设计」&quot;">​</a></h3><p>这背后是大模型的过度对齐问题。</p><p>大模型训练时见过太多复杂场景，对简单任务也会本能地加边缘情况处理，加错误处理，加注释和文档，用更复杂的设计模式。</p><p>写一个简单的 helper 函数，Sonnet 可能给你 30 行，Haiku 给你 10 行。后者在大多数场景反而更对。</p><p>我自己的判断标准是任务的「认知步骤数」：</p><p>1 到 2 步的活儿扔 Haiku 5 步以上留给 Sonnet 或 Opus 10 步以上才开 ultrathink</p><p>不要无脑用最强模型，最强模型对简单任务有「设计过度」的副作用，输出的代码后期还要花时间删冗余。</p><h3 id="六、-loop-挂-3-天的真正用法是-monitoring-不是写代码" tabindex="-1">六、/loop 挂 3 天的真正用法是 monitoring，不是写代码 <a class="header-anchor" href="#六、-loop-挂-3-天的真正用法是-monitoring-不是写代码" aria-label="Permalink to &quot;六、/loop 挂 3 天的真正用法是 monitoring，不是写代码&quot;">​</a></h3><p>很多人看到 /loop 第一反应是「让 Claude 连续写 3 天代码」，其实不是。</p><p>/loop 真正的用法是把 Claude 从同步工具变成异步同事。它在那挂着，定期检查状态，有事叫你。</p><p>好的 /loop 任务有几个特征：</p><p>输入是状态，不是动作 输出是「有事/没事」的判断 处理时间不连续，可以等</p><p>比如每 10 分钟看一下 CI 是不是过了，没过分析失败原因，每小时扫一下数据库慢查询，每天看一遍 PR review 队列。这些以前是「我得记得去看」的事，现在变成「Claude 看到再叫我」。</p><p>这是 Claude 从写代码工具升级成值班同事的关键。</p><h3 id="把这些串起来看" tabindex="-1">把这些串起来看 <a class="header-anchor" href="#把这些串起来看" aria-label="Permalink to &quot;把这些串起来看&quot;">​</a></h3><p>如果只看 32 个技巧，你最多能复述操作。但如果把上面这 6 个点连起来看，你会发现 Nate Herk 真正的心法，是一个心智模型：</p><p>把 Claude Code 当成一个「有限注意力，有限时间，有性格」的同事来管理，不要当成「无限算力的工具」来用。</p><p>所有技巧背后都是这个心智模型在起作用：</p><p>注意力有限，所以要做 context 管理，对应的是 /compact、/clear、sub agent 隔离</p><p>时间有限，所以要异步化，对应的是 /loop、agent team、多 session 并行</p><p>有性格，所以要 prompt 沟通，对应的是 plan mode，让它反问，junior 同事心态</p><p>心智模型一旦换过来，剩下的技巧都是延伸，自己也能想出来。</p><p>我自己用 Claude Code 写代码差不多大半年了，最大的认知升级不是某个具体技巧，而是从「我用一个工具」变成「我管一个同事」。这两种心态出来的代码质量，效率，token 消耗，差着一个数量级。</p><p>*注意，此文章是我同 AI 共同创作</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：不是32个技巧，而是一个心智模型——把Claude Code当有限注意力的同事来管理，不是无限工具。所有技巧背后都是这个模式：有限注意力→context管理、有限时间→异步化、有性格→prompt沟通。</p><h3 id="核心论点" tabindex="-1">核心论点 <a class="header-anchor" href="#核心论点" aria-label="Permalink to &quot;核心论点&quot;">​</a></h3><ul><li>Descriptive prompts (解释why) vs imperative prompts (命令what)：前者触发深层推理(chain-of-thought)，后者只是浅层pattern-match</li><li>60%阈值不是省token，是对抗&quot;lost in the middle&quot;现象：LLM注意力在长context中呈U形曲线，中间部分最易被忽视</li><li>Exit-restart (fail-fast)是token经济学：被污染context中修正的成本是重新开始的2-3倍</li><li>Sub-agents的核心价值是context隔离(tree structure)而非并行，让探索失败不污染主线</li><li>使用小模型(Haiku)避免&quot;过度设计&quot;：大模型会本能地加错误处理、文档、复杂模式，反而在简单任务上失效</li><li>/loop的真正用法是异步监控状态变化(CI结果、PR队列)，不是代码生成</li></ul><h3 id="关键数据-工具" tabindex="-1">关键数据/工具 <a class="header-anchor" href="#关键数据-工具" aria-label="Permalink to &quot;关键数据/工具&quot;">​</a></h3><ul><li>32 tips in 16 min (Nate Herk YouTube video)</li><li>Stanford 2023论文：&quot;lost in the middle&quot;——LLM在长context中的注意力衰减规律</li><li>60%作为context警戒线（非成本阈值）</li><li>Exit-restart成本溢价：2-3倍</li><li>Haiku vs Sonnet权衡：Haiku输出往往更简洁、更少冗余</li><li>认知步骤启发式：1-2步→Haiku, 5+→Sonnet, 10+→ultrathink</li></ul><h3 id="批判性观察" tabindex="-1">批判性观察 <a class="header-anchor" href="#批判性观察" aria-label="Permalink to &quot;批判性观察&quot;">​</a></h3><ul><li>32个技巧看似零散，实则全是&quot;从使用工具→管理同事&quot;这一心智模型转变的延伸</li><li>大多数团队优化单个技巧而错过了系统级的思维改变</li><li>&quot;Fail-fast&quot;原则(遇到走偏立刻ESC重开)与工程直觉(再试一次修正)相悖，需要组织文化支持</li><li>关键洞察：技巧表象背后是资源约束的深层理解(注意力、时间、AI人格)</li></ul><hr><h2 id="评分" tabindex="-1">评分 <a class="header-anchor" href="#评分" aria-label="Permalink to &quot;评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>分数</th><th>说明</th></tr></thead><tbody><tr><td>A. Workspace 可行动性 (30%)</td><td>9/10</td><td>直接对应cc-workspace的CLAUDE.md架构：/compact阈值、sub-agent策略、prompt设计、context管理——所有规则已在用。核心框架(colleague-management model)应升格为设计方针。</td></tr><tr><td>B. 创新性 (20%)</td><td>8/10</td><td>&quot;管理同事而非使用工具&quot;的心智模型转变对多数Claude Code用户而言是新颖的。Stanford论文(2023)虽已发表，但与60%规则的连接在实践中少见。</td></tr><tr><td>C. 证据品质 (20%)</td><td>8/10</td><td>引用Stanford论文、提供具体成本分析(2-3x restart溢价)、量化启发式(32 tips、认知步骤分级)。缺少benchmark但逻辑自洽，基于作者6个月实战经验。</td></tr><tr><td>D. 技术深度 (15%)</td><td>8/10</td><td>深入机制层面：U-curve注意力、Draft.js内容解析、confirmation bias在polluted context的影响。可更深入tokenizer行为，但足以指导实践。</td></tr><tr><td>E. 泛化性 (15%)</td><td>9/10</td><td>原则跨越所有Claude Code工作流(研究、代码、规划)。非特定领域，不依赖Nate Herk视频，转移到任何长context agent管理场景。</td></tr><tr><td><strong>加权总分</strong></td><td><strong>8.4/10</strong></td><td>A×0.3 + B×0.2 + C×0.2 + D×0.15 + E×0.15 = 8.4</td></tr></tbody></table><p><strong>整合决策</strong>：RULE</p><p><strong>理由</strong>：总分8.4&gt;6.0。主要贡献不是技巧集合，而是可泛化的心智模型(colleague-management)，应升格为架构原则而非单篇技巧。此模型直接影响subagent-strategy、prompt工程、context管理等多条既有规则的应用方式，建议作为<code>.claude/rules/agent-mindset.md</code>补充到常驻载入层。</p><p>*注意：此文章是作者与AI共同创作。</p><hr><p><strong>归档完成</strong>。此文档编码了Nate Herk视频与cc-workspace实践间的关键连接。核心心智模型(&quot;有限注意力的同事&quot;)应作为所有Claude Code工作流的设计基准。建议后续在CLAUDE.md的「核心工作流」章节中加入此模型的显式陈述。</p>',76)])])}const m=e(n,[["render",l]]);export{u as __pageData,m as default};
